t.script:
//
(function () {
    'use strict';
    var card = document.getElementById('slaTimerCard');
    if (!card) return;
    var deadline = new Date(card.getAttribute('data-deadline')).getTime();
    var duration = parseInt(card.getAttribute('data-duration'), 10) * 1000;
    var iconEl   = document.getElementById('slaIcon');
    var titleEl  = document.getElementById('slaCardTitle');
    var numEl    = document.getElementById('slaBigNumber');
    var lblEl    = document.getElementById('slaBigLabel');
    var fillEl   = document.getElementById('slaProgFill');
    var pctEl    = document.getElementById('slaProgPct');
    var ICON_HTML  = { 'on-track': '<i class="bi bi-clock-fill"></i>', 'at-risk': '<i class="bi bi-exclamation-triangle-fill"></i>', 'breached': '<i class="bi bi-x-octagon-fill"></i>' };
    var ICON_STYLE = { 'on-track': 'background:var(--green-bg);color:var(--green)', 'at-risk': 'background:var(--amber-bg);color:var(--amber)', 'breached': 'background:var(--red-bg);color:var(--red)' };
    var TITLES     = { 'on-track': 'SLA On Track', 'at-risk': 'SLA At Risk \u26a0\ufe0f', 'breached': 'SLA Breached!' };
    function pad(n) { return String(n).padStart(2, '0'); }
    function getState(rem) { if (rem <= 0) return 'breached'; if (rem <= 7200000) return 'at-risk'; return 'on-track'; }
    function tick() {
        var now = Date.now(); var rem = deadline - now; var st = getState(rem);
        card.className = 'sla-card ' + st;
        iconEl.setAttribute('style', ICON_STYLE[st]); iconEl.innerHTML = ICON_HTML[st];
        titleEl.textContent = TITLES[st];
        if (rem <= 0) {
            var over = Math.abs(rem);
            numEl.textContent = (Math.floor(over/3600000) > 0 ? pad(Math.floor(over/3600000)) + ':' : '') + pad(Math.floor((over%3600000)/60000)) + ':' + pad(Math.floor((over%60000)/1000));
            lblEl.textContent = 'past deadline';
        } else {
            numEl.textContent = pad(Math.floor(rem/3600000)) + ':' + pad(Math.floor((rem%3600000)/60000)) + ':' + pad(Math.floor((rem%60000)/1000));
            lblEl.textContent = 'remaining';
        }
        var pct = Math.min(100, Math.max(0, Math.round((duration - rem) / duration * 100)));
        fillEl.style.width = pct + '%'; pctEl.textContent = pct + '%';
    }
    tick(); setInterval(tick, 1000);
})();
//

//
document.addEventListener('DOMContentLoaded', function () {

    function showToast(msg, type) {
        type = type || 'success';
        var icons = { success: 'bi-check-circle-fill', info: 'bi-info-circle-fill', warning: 'bi-exclamation-triangle-fill' };
        var tc = document.getElementById('toastContainer');
        var t  = document.createElement('div');
        t.className = 'toast-item ' + type;
        t.innerHTML = '<i class="bi ' + (icons[type] || icons.success) + '"></i>' + msg;
        tc.appendChild(t);
        setTimeout(function () { t.style.opacity = '0'; t.style.transform = 'translateY(8px)'; t.style.transition = '0.3s'; setTimeout(function(){ t.remove(); }, 300); }, 3200);
    }

    var sidebar     = document.getElementById('mainSidebar');
    var collapseBtn = document.getElementById('sidebarCollapseBtn');
    var STORAGE_KEY = 'sd_sidebar_collapsed';
    if (localStorage.getItem(STORAGE_KEY) === 'true') {
        sidebar.style.transition = 'none';
        sidebar.classList.add('collapsed');
        requestAnimationFrame(function () { requestAnimationFrame(function () { sidebar.style.transition = ''; }); });
    }
    collapseBtn.addEventListener('click', function () {
        var isNowCollapsed = sidebar.classList.toggle('collapsed');
        localStorage.setItem(STORAGE_KEY, isNowCollapsed ? 'true' : 'false');
    });

    setTimeout(function () {
        ['alertSuccess','alertDanger'].forEach(function (id) { var el = document.getElementById(id); if (el) el.remove(); });
    }, 5000);

    var panels   = document.querySelectorAll('.tab-panel');
    var navItems = document.querySelectorAll('.sidebar-item[data-panel]');
    var panelIds = Array.from(navItems).map(function(n){ return n.getAttribute('data-panel'); });

    function showPanel(panelId) {
        panels.forEach(function (p)   { p.classList.remove('active'); });
        navItems.forEach(function (n) { n.classList.remove('active'); });
        var target = document.getElementById(panelId);
        if (target) target.classList.add('active');
        var btn = document.querySelector('.sidebar-item[data-panel="' + panelId + '"]');
        if (btn) btn.classList.add('active');
        window.scrollTo({ top: 0, behavior: 'smooth' });
    }
    navItems.forEach(function (btn) {
        btn.addEventListener('click', function () { showPanel(this.getAttribute('data-panel')); });
    });

    document.addEventListener('keydown', function (e) {
        if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.tagName === 'SELECT') return;
        var idx = parseInt(e.key, 10) - 1;
        if (idx >= 0 && idx < panelIds.length) showPanel(panelIds[idx]);
    });

    var fileFilterBtns = document.querySelectorAll('.files-filter-btn');
    fileFilterBtns.forEach(function (btn) {
        btn.addEventListener('click', function () {
            fileFilterBtns.forEach(function(b){ b.classList.remove('active'); });
            this.classList.add('active');
            var filter = this.getAttribute('data-file-filter');
            document.querySelectorAll('#filesGrid .file-card').forEach(function (card) {
                card.style.display = (filter === 'all' || card.getAttribute('data-file-type') === filter) ? '' : 'none';
            });
        });
    });

    var actFilterBtns = document.querySelectorAll('.act-filter-btn');
    actFilterBtns.forEach(function (btn) {
        btn.addEventListener('click', function () {
            actFilterBtns.forEach(function(b){ b.classList.remove('active'); });
            this.classList.add('active');
            var filter = this.getAttribute('data-act-filter');
            document.querySelectorAll('.act-item').forEach(function (item) {
                item.classList.toggle('hidden', filter !== 'all' && item.getAttribute('data-act-type') !== filter);
            });
        });
    });

    var deptTabs    = document.querySelectorAll('.dept-tab');
    var personCards = document.querySelectorAll('.person-card');
    var selectedPerson = null;

    deptTabs.forEach(function (tab) {
        tab.addEventListener('click', function () {
            deptTabs.forEach(function(t){ t.classList.remove('active'); });
            this.classList.add('active');
            var dept = this.getAttribute('data-dept');
            selectedPerson = null;
            document.getElementById('forwardSelection').textContent = 'No person selected';
            personCards.forEach(function (card) {
                card.classList.remove('selected');
                card.style.display = card.getAttribute('data-dept') === dept ? '' : 'none';
            });
        });
    });

    personCards.forEach(function (card) {
        card.addEventListener('click', function () {
            personCards.forEach(function(c){ c.classList.remove('selected'); });
            this.classList.add('selected');
            selectedPerson = this.querySelector('.person-name').textContent;
            document.getElementById('forwardSelection').textContent = 'Selected: ' + selectedPerson;
        });
    });

    document.getElementById('forwardBtn').addEventListener('click', function () {
        if (!selectedPerson) { showToast('Please select a person to forward to.', 'warning'); return; }
        showToast('Ticket forwarded to <strong>' + selectedPerson + '</strong>.', 'success');
    });

    document.querySelectorAll('.doc-item-header').forEach(function (header) {
        header.addEventListener('click', function () {
            var item = this.closest('.doc-item');
            item.classList.toggle('expanded');
        });
    });

    var docCatBtns = document.querySelectorAll('.docs-cat-btn');
    docCatBtns.forEach(function (btn) {
        btn.addEventListener('click', function () {
            docCatBtns.forEach(function(b){ b.classList.remove('active'); });
            this.classList.add('active');
            var cat = this.getAttribute('data-doc-cat');
            filterDocs(cat, document.getElementById('docsSearch').value.trim().toLowerCase());
        });
    });

    document.getElementById('docsSearch').addEventListener('input', function () {
        var activeCat = document.querySelector('.docs-cat-btn.active').getAttribute('data-doc-cat');
        filterDocs(activeCat, this.value.trim().toLowerCase());
    });

    function filterDocs(cat, search) {
        document.querySelectorAll('.doc-item').forEach(function (item) {
            var matchCat    = cat === 'all' || item.getAttribute('data-doc-cat') === cat;
            var matchSearch = !search || item.getAttribute('data-doc-title').toLowerCase().includes(search);
            item.classList.toggle('hidden', !(matchCat && matchSearch));
        });
    }

    var messageIdToDelete = null;
    var deleteModal = new bootstrap.Modal(document.getElementById('deleteMessageModal'));
    document.querySelectorAll('.msg-action-btn.delete').forEach(function (btn) {
        btn.addEventListener('click', function () { messageIdToDelete = this.getAttribute('data-message-id'); deleteModal.show(); });
    });
    document.getElementById('confirmDeleteBtn').addEventListener('click', function () {
        if (!messageIdToDelete) return;
        fetch('/customer_support/ticket/message/' + messageIdToDelete + '/delete', { method: 'POST', body: new FormData() })
        .then(function (r) { return r.json(); })
        .then(function (data) {
            if (data.success) {
                var el = document.querySelector('.message-item[data-message-id="' + messageIdToDelete + '"]');
                if (el) el.remove();
                deleteModal.hide();
                showToast('Message deleted successfully.', 'info');
            } else { alert('Error: ' + (data.error || 'Failed to delete message')); }
        });
    });

    document.querySelectorAll('.msg-action-btn.edit').forEach(function (btn) {
        btn.addEventListener('click', function () {
            var mid  = this.getAttribute('data-message-id');
            var body = document.querySelector('.msg-body[data-message-id="' + mid + '"]');
            var form = document.querySelector('.msg-edit-form[data-message-id="' + mid + '"]');
            var ta   = form.querySelector('.msg-edit-textarea');
            var tmp  = document.createElement('div');
            tmp.innerHTML = body.innerHTML;
            ta.value = (tmp.textContent || tmp.innerText || '').trim();
            body.style.display = 'none'; form.style.display = 'block'; ta.focus();
        });
    });
    document.querySelectorAll('.cancel-edit-btn').forEach(function (btn) {
        btn.addEventListener('click', function () {
            var mid = this.getAttribute('data-message-id');
            document.querySelector('.msg-body[data-message-id="' + mid + '"]').style.display = '';
            document.querySelector('.msg-edit-form[data-message-id="' + mid + '"]').style.display = 'none';
        });
    });
    document.querySelectorAll('.save-edit-btn').forEach(function (btn) {
        btn.addEventListener('click', function () {
            var mid     = this.getAttribute('data-message-id');
            var form    = document.querySelector('.msg-edit-form[data-message-id="' + mid + '"]');
            var newBody = form.querySelector('.msg-edit-textarea').value.trim();
            if (!newBody) { alert('Message cannot be empty'); return; }
            var fd = new FormData();
            fd.append('new_body', newBody);
            fetch('/customer_support/ticket/message/' + mid + '/edit', { method: 'POST', body: fd })
            .then(function (r) { return r.json(); })
            .then(function (data) {
                if (data.success) {
                    var body = document.querySelector('.msg-body[data-message-id="' + mid + '"]');
                    body.innerHTML = newBody; body.style.display = '';
                    document.querySelector('.msg-edit-form[data-message-id="' + mid + '"]').style.display = 'none';
                    showToast('Message updated.', 'success');
                } else { alert('Error: ' + (data.error || 'Failed to update')); }
            });
        });
    });

});
// bfcache guard
window.addEventListener('pageshow', function (e) {
    if (e.persisted) { window.location.reload(); }
});
// popstate guard: redirect to dashboard if back/forward leaves the portal
window.addEventListener('popstate', function () {
    if (!window.location.pathname.startsWith('/customer_support/')) {
        window.location.replace('/customer_support/dashboard');
    }
});
//
